 #!/usr/bin/perl -pi.bak use strict; use warnings; # original my $o = quotemeta << 'EOF'; checked_command: function(orig_cmd) { Proxmox.Utils.API2Request( { url: '/nodes/localhost/subscription', method: 'GET', failure: function(response, opts) { Ext.Msg.alert(gettext('Error'), response.htmlStatus); }, success: function(response, opts) { let res = response.result; if (res === null || res === undefined || !res || res .data.status.toLowerCase() !== 'active') { Ext.Msg.show({ title: gettext('No valid subscription'), icon: Ext.Msg.WARNING, message: Proxmox.Utils.getNoSubKeyHtml(res.data.url), buttons: Ext.Msg.OK, callback: function(btn) { if (btn !== 'ok') { return; } orig_cmd(); }, }); } else { orig_cmd(); } }, }, ); }, EOF # replacement my $r = << 'EOF'; checked_command: function(orig_cmd) { Proxmox.Utils.API2Request( { url: '/nodes/localhost/subscription', method: 'GET', failure: function(response, opts) { Ext.Msg.alert(gettext('Error'), response.htmlStatus); }, success: function(response, opts) { orig_cmd(); }, }, ); }, EOF BEGIN { undef $/; } s/$o/$r/; Shebang   arguments provide for execution of the script over input, sed-style (-p), and also guarantee a backup copy is retained (-i.bak).
Original pattern ($o)and its replacement ($r) are assigned to variables using HEREDOC   notation in full, the original gets non-word characters escaped (quotemeta) for use with regular expressions.
The entire replacement is in a single shot on multi-line (undef $/;) pattern, where original is substituted for replacement (s/$o/$r/;) or, if not found, nothing is modified.
